     1→#!/usr/bin/env node
     2→/**
     3→ * Claude Code stdin hook handler.
     4→ *
     5→ * Reads a hook event from stdin, maintains a markdown sessions table, and
     6→ * writes a JSON response to stdout.
     7→ *
     8→ * Configure in ~/.claude/settings.json:
     9→ *
    10→ *   {
    11→ *     "hooks": {
    12→ *       "PreToolUse": [{
    13→ *         "matcher": ".*",
    14→ *         "hooks": [{ "type": "command", "command": "claude-hook-handler --sessions ~/.claude/sessions.md" }]
    15→ *       }],
    16→ *       ...
    17→ *     }
    18→ *   }
    19→ */
    20→import Anthropic from "@anthropic-ai/sdk";
    21→import {
    22→  readFileSync,
    23→  writeFileSync,
    24→  appendFileSync,
    25→  existsSync,
    26→  mkdirSync,
    27→  renameSync,
    28→  readdirSync,
    29→  unlinkSync,
    30→} from "fs";
    31→import { dirname, join, resolve, basename } from "path";
    32→import { homedir } from "os";
    33→import { execSync, spawnSync } from "child_process";
    34→import { Command } from "commander";
    35→import type {
    36→  HookInput,
    37→  SyncHookJSONOutput,
    38→  PreToolUseHookInput,
    39→  PostToolUseHookInput,
    40→  PostToolUseFailureHookInput,
    41→  SubagentStartHookInput,
    42→} from "@anthropic-ai/claude-agent-sdk";
    43→import {
    44→  getDb,
    45→  readStateFromDb,
    46→  writeStateToDb,
    47→  type State,
    48→  type SessionRecord,
    49→  type PendingToolUseRecord,
    50→} from "./db.js";
    51→
    52→// Re-export PendingToolUseRecord under the local alias used throughout
    53→type PendingToolUse = PendingToolUseRecord;
    54→
    55→// ─── Path helpers ─────────────────────────────────────────────────────────────
    56→
    57→function expandHome(p: string): string {
    58→  return p.startsWith("~/") ? join(homedir(), p.slice(2)) : resolve(p);
    59→}
    60→
    61→// ─── Config file ──────────────────────────────────────────────────────────────
    62→
    63→const CONFIG_PATH = join(homedir(), ".claude", "hook-handler.json");
    64→
    65→interface Config {
    66→  anthropicApiKey?: string;
    67→  /**
    68→   * Path to a git repository where session logs are committed.
    69→   * When set, sessions.md and the sessions/ folder are stored inside this
    70→   * directory instead of the default ~/.claude location.
    71→   * The --sessions CLI flag still overrides this value.
    72→   *
    73→   * Example: { "repository": "~/notes/claude-sessions" }
    74→   */
    75→  repository?: string;
    76→}
    77→
    78→function loadConfig(): Config {
    79→  try {
    80→    const raw = readFileSync(CONFIG_PATH, "utf8");
    81→    const config = JSON.parse(raw) as Config;
    82→    if (config.anthropicApiKey && !process.env.ANTHROPIC_API_KEY) {
    83→      process.env.ANTHROPIC_API_KEY = config.anthropicApiKey;
    84→    }
    85→    return config;
    86→  } catch {
    87→    // Config file is optional — no-op if missing or unreadable
    88→    return {};
    89→  }
    90→}
    91→
    92→// ─── Git user ─────────────────────────────────────────────────────────────────
    93→
    94→interface GitUser {
    95→  name?: string;
    96→  email?: string;
    97→}
    98→
    99→function gitUser(): GitUser {
   100→  const get = (key: string): string | undefined => {
   101→    try {
   102→      return execSync(`git config --global ${key}`, {
   103→        encoding: "utf8",
   104→        stdio: ["ignore", "pipe", "ignore"],
   105→      }).trim() || undefined;
   106→    } catch { return undefined; }
   107→  };
   108→  return { name: get("user.name"), email: get("user.email") };
   109→}
   110→
   111→// ─── Git repo detection ───────────────────────────────────────────────────────
   112→
   113→interface RepoInfo {
   114→  repoRoot: string;
   115→  repoName: string;
   116→}
   117→
   118→function detectRepo(cwd: string): RepoInfo | undefined {
   119→  try {
   120→    const root = execSync("git rev-parse --show-toplevel", {
   121→      cwd,
   122→      encoding: "utf8",
   123→      stdio: ["ignore", "pipe", "ignore"],
   124→    }).trim();
   125→    return { repoRoot: root, repoName: basename(root) };
   126→  } catch {
   127→    return undefined;
   128→  }
   129→}
   130→
   131→// ─── Markdown rendering ───────────────────────────────────────────────────────
   132→
   133→function fmt(iso: string): string {
   134→  const d = new Date(iso);
   135→  const dd  = String(d.getDate()).padStart(2, "0");
   136→  const mm  = String(d.getMonth() + 1).padStart(2, "0");
   137→  const yy  = String(d.getFullYear()).slice(2);
   138→  const hh  = String(d.getHours()).padStart(2, "0");
   139→  const min = String(d.getMinutes()).padStart(2, "0");
   140→  return `${dd}/${mm}/${yy} ${hh}:${min}`;
   141→}
   142→
   143→function escapeCell(s: string): string {
   144→  return s.replace(/\|/g, "\\|").replace(/\n/g, " ");
   145→}
   146→
   147→function renderMarkdown(state: State): string {
   148→  const sessions = Object.values(state.sessions).sort((a, b) =>
   149→    b.updatedAt.localeCompare(a.updatedAt),
   150→  );
   151→
   152→  const updatedAt = `${fmt(new Date().toISOString())} UTC`;
   153→
   154→  if (sessions.length === 0) {
   155→    return (
   156→      `# Claude Code Sessions\n\n` +
   157→      `*No active sessions.*\n\n` +
   158→      `*Last updated: ${updatedAt}*\n`
   159→    );
   160→  }
   161→
   162→  const header = "| Session ID | User | Repo | Summary | Keywords | Started | Last Updated |";
   163→  const divider = "|---|---|---|---|---|---|---|";
   164→  const rows = sessions.map((s) => {
   165→    const id = `[\`${s.sessionId.slice(0, 8)}…\`](sessions/${s.sessionId}.md)`;
   166→    const user = escapeCell(
   167→      s.gitUserName && s.gitUserEmail ? `${s.gitUserName} <${s.gitUserEmail}>`
   168→      : s.gitUserName ?? s.gitUserEmail ?? "",
   169→    );
   170→    const repo = escapeCell(s.repoName ?? s.cwd.split("/").pop() ?? s.cwd);
   171→    const summary = escapeCell(
   172→      s.summary ?? s.prompt?.slice(0, 80) ?? "*waiting for prompt…*",
   173→    );
   174→    const keywords = s.keywords?.length
   175→      ? s.keywords.map((k) => `\`${escapeCell(k)}\``).join(" ")
   176→      : "";
   177→    return `| ${id} | ${user} | ${repo} | ${summary} | ${keywords} | ${fmt(s.startedAt)} | ${fmt(s.updatedAt)} |`;
   178→  });
   179→
   180→  return [
   181→    "# Claude Code Sessions",
   182→    "",
   183→    header,
   184→    divider,
   185→    ...rows,
   186→    "",
   187→    `*Last updated: ${updatedAt}*`,
   188→    "",
   189→  ].join("\n");
   190→}
   191→
   192→function writeMarkdown(sessionsPath: string, state: State): void {
   193→  mkdirSync(dirname(sessionsPath), { recursive: true });
   194→  const tmp = sessionsPath + ".tmp";
   195→  writeFileSync(tmp, renderMarkdown(state), "utf8");
   196→  renameSync(tmp, sessionsPath);
   197→}
   198→
   199→// ─── Per-session event log ────────────────────────────────────────────────────
   200→
   201→// Always omit — structural noise with no reader value
   202→const SKIP_COMMON = new Set([
   203→  "session_id", "hook_event_name", "transcript_path", "tool_use_id",
   204→]);
   205→// Also omit for collapsed events (same for every tool call — not useful per-event)
   206→const SKIP_NOISE = new Set([...SKIP_COMMON, "cwd", "permission_mode"]);
   207→
   208→const IMPORTANT_EVENTS = new Set([
   209→  "UserPromptSubmit", "Stop", "SessionEnd",
   210→]);
   211→
   212→const SKIP_EVENTS = new Set([
   213→  "SessionStart",
   214→]);
   215→
   216→/** Extract a short hint string from tool_input for the <summary> line. */
   217→function toolSummaryHint(toolName: string, toolInput: unknown): string {
   218→  if (!toolInput || typeof toolInput !== "object") return "";
   219→  const inp = toolInput as Record<string, unknown>;
   220→  const str = (k: string): string | undefined =>
   221→    typeof inp[k] === "string" ? String(inp[k]) : undefined;
   222→  switch (toolName) {
   223→    case "Read":      return str("file_path") ?? "";
   224→    case "Write":     return str("file_path") ?? "";
   225→    case "Edit":      return str("file_path") ?? "";
   226→    case "Bash":      return (str("command") ?? "").slice(0, 70);
   227→    case "Glob":      return str("pattern") ?? "";
   228→    case "Grep":      return str("pattern") ?? "";
   229→    case "WebFetch":  return str("url") ?? "";
   230→    case "WebSearch": return str("query") ?? "";
   231→    default:          return "";
   232→  }
   233→}
   234→
   235→/** Render fields for an event, skipping the given skip-set. */
   236→function renderFields(
   237→  input: HookInput,
   238→  skip: Set<string>,
   239→  childLogRelPath?: string,
   240→): string[] {
   241→  const lines: string[] = [];
   242→  for (const [key, value] of Object.entries(input)) {
   243→    if (skip.has(key) || value === undefined) continue;
   244→    if (key === "prompt" || key === "message" || key === "last_assistant_message") {
   245→      lines.push(`**${key}:**`, "");
   246→      for (const line of String(value).split("\n")) lines.push(`> ${line}`);
   247→      lines.push("");
   248→    } else if (key === "tool_input" || key === "tool_response") {
   249→      const s = JSON.stringify(value, null, 2);
   250→      lines.push(`**${key}:**`, "```json", s.length > 600 ? s.slice(0, 600) + "\n…" : s, "```", "");
   251→    } else if (key === "agent_id" && childLogRelPath) {
   252→      lines.push(`- **${key}:** [\`${String(value)}\`](${childLogRelPath})`);
   253→    } else {
   254→      lines.push(`- **${key}:** \`${String(value)}\``);
   255→    }
   256→  }
   257→  return lines;
   258→}
   259→
   260→/** Important events: H2 heading, full field list, horizontal rule. */
   261→function formatImportantEvent(input: HookInput): string {
   262→  const ts = fmt(new Date().toISOString());
   263→  const name = input.hook_event_name;
   264→  const sym = EVENT_SYMBOL[name] ?? "◆";
   265→  const fields = renderFields(input, SKIP_COMMON);
   266→  return [`## ${sym} ${name}`, "", `<small>${ts}</small>`, "", ...fields, "---", ""].join("\n");
   267→}
   268→
   269→/** UserPromptSubmit: "<User> prompted:" followed by the prompt as a blockquote. */
   270→function formatPromptEvent(input: HookInput, rec: SessionRecord | undefined): string {
   271→  const ts = fmt(new Date().toISOString());
   272→  const user = rec?.gitUserName ?? rec?.gitUserEmail ?? "User";
   273→  const prompt = "prompt" in input ? String(input.prompt) : "";
   274→  const lines: string[] = [`## → **${user} prompted:**`, "", `<small>${ts}</small>`, ""];
   275→  for (const line of prompt.split("\n")) lines.push(`> ${line}`);
   276→  lines.push("", "---", "");
   277→  return lines.join("\n");
   278→}
   279→
   280→/** Stop / Notification: "Claude wrote:" followed by the message as a blockquote. */
   281→function formatClaudeMessageEvent(input: HookInput): string {
   282→  const ts = fmt(new Date().toISOString());
   283→  const sym = EVENT_SYMBOL[input.hook_event_name] ?? "◆";
   284→  const message =
   285→    "last_assistant_message" in input && input.last_assistant_message
   286→      ? String(input.last_assistant_message)
   287→      : "message" in input && input.message
   288→      ? String(input.message)
   289→      : "";
   290→
   291→  if (!message) return formatImportantEvent(input);
   292→
   293→  const lines: string[] = [`## ${sym} **Claude wrote:**`, "", `<small>${ts}</small>`, ""];
   294→  for (const line of message.split("\n")) lines.push(`> ${line}`);
   295→  lines.push("", "---", "");
   296→  return lines.join("\n");
   297→}
   298→
   299→/** Non-critical events: collapsed <details> block. */
   300→function formatCollapsibleEvent(input: HookInput, childLogRelPath?: string): string {
   301→  const ts = fmt(new Date().toISOString());
   302→  const name = input.hook_event_name;
   303→  const sym = EVENT_SYMBOL[name] ?? "◆";
   304→  const fields = renderFields(input, SKIP_NOISE, childLogRelPath);
   305→  return [
   306→    `<details>`,
   307→    `<summary><small>${name}</small></summary>`,
   308→    "",
   309→    `<small>${ts}</small>`,
   310→    "",
   311→    ...fields,
   312→    `</details>`,
   313→    "",
   314→    "",
   315→  ].join("\n");
   316→}
   317→
   318→/** Merged Pre+PostToolUse: collapsed <details> with success/failure indicator. */
   319→function formatMergedToolUse(
   320→  pending: PendingToolUse,
   321→  post: PostToolUseHookInput | PostToolUseFailureHookInput,
   322→): string {
   323→  const failed = post.hook_event_name === "PostToolUseFailure";
   324→  const statusSym = failed ? "✗" : "✓";
   325→  const hint = toolSummaryHint(pending.tool_name, pending.tool_input);
   326→  const hintStr = hint ? ` · \`${hint.replace(/`/g, "'").replace(/\s+/g, " ")}\`` : "";
   327→  const endTs = fmt(new Date().toISOString());
   328→
   329→  const lines: string[] = [
   330→    `<details>`,
   331→    `<summary><small>${statusSym} ${pending.tool_name}${hintStr}</small></summary>`,
   332→    "",
   333→    `<small>${pending.startedAt} → ${endTs}</small>`,
   334→    "",
   335→  ];
   336→
   337→  if (pending.tool_input !== undefined) {
   338→    const s = JSON.stringify(pending.tool_input, null, 2);
   339→    lines.push("**input:**", "```json", s.length > 600 ? s.slice(0, 600) + "\n…" : s, "```", "");
   340→  }
   341→
   342→  if (failed && "error" in post && post.error) {
   343→    lines.push(`**error:** \`${String(post.error)}\``, "");
   344→  } else if ("tool_response" in post && post.tool_response !== undefined) {
   345→    const s =
   346→      typeof post.tool_response === "string"
   347→        ? post.tool_response
   348→        : JSON.stringify(post.tool_response, null, 2);
   349→    lines.push("**output:**", "```", s.length > 400 ? s.slice(0, 400) + "\n…" : s, "```", "");
   350→  }
   351→
   352→  lines.push(`</details>`, "", "");
   353→  return lines.join("\n");
   354→}
   355→
   356→function sessionLogPath(sessionsPath: string, sessionId: string): string {
   357→  return join(dirname(sessionsPath), "sessions", `${sessionId}.md`);
   358→}
   359→
   360→// ─── Log rotation ─────────────────────────────────────────────────────────────
   361→
   362→function archiveTimestamp(): string {
   363→  const d = new Date();
   364→  return (
   365→    String(d.getFullYear()) +
   366→    String(d.getMonth() + 1).padStart(2, "0") +
   367→    String(d.getDate()).padStart(2, "0") +
   368→    "-" +
   369→    String(d.getHours()).padStart(2, "0") +
   370→    String(d.getMinutes()).padStart(2, "0")
   371→  );
   372→}
   373→
   374→/**
   375→ * If `logPath` exceeds `maxLines` lines, rename it to a timestamped archive,
   376→ * then write a fresh file containing only the header (with an "← prev" link).
   377→ * Returns the archive path if rotation happened, undefined otherwise.
   378→ */
   379→function rotateSessionLog(logPath: string, maxLines: number): string | undefined {
   380→  if (!existsSync(logPath)) return undefined;
   381→
   382→  const content = readFileSync(logPath, "utf8");
   383→  if (content.split("\n").length <= maxLines) return undefined;
   384→
   385→  // Build archive filename next to the current file
   386→  const dir = dirname(logPath);
   387→  const base = basename(logPath, ".md");
   388→  const archiveName = `${base}-${archiveTimestamp()}.md`;
   389→  const archivePath = join(dir, archiveName);
   390→
   391→  // Rename current file → archive
   392→  renameSync(logPath, archivePath);
   393→
   394→  // Append a forward link to the bottom of the archived file
   395→  const nextName = basename(logPath);
   396→  appendFileSync(archivePath, `\n---\n\n<small>[→ next](${nextName})</small>\n`, "utf8");
   397→
   398→  // Extract header: everything before the first event entry
   399→  const firstEventIdx = content.search(/^(?:## |<details>)/m);
   400→  let header = firstEventIdx !== -1 ? content.slice(0, firstEventIdx) : content;
   401→
   402→  // Inject / update the "← prev" link next to the session ID in the <sub> line
   403→  const prevLink = `[← prev](${archiveName})`;
   404→  if (header.includes("[← prev]")) {
   405→    // Update existing link to point to the new archive
   406→    header = header.replace(/\[← prev\]\([^)]*\)/, prevLink);
   407→  } else if (header.includes("<sub>")) {
   408→    // Insert after the backtick-wrapped session ID
   409→    header = header.replace(/(<sub>)(`[^`]+`)/, `$1$2 · ${prevLink}`);
   410→  } else {
   411→    // Fallback for bare initial header (pre-UserPromptSubmit)
   412→    header = header.replace(
   413→      /^(# Session `[^`]+`\n\n)/m,
   414→      `$1<small>${prevLink}</small>\n\n`,
   415→    );
   416→  }
   417→
   418→  writeFileSync(logPath, header, "utf8");
   419→  return archivePath;
   420→}
   421→
   422→function updateLogHeader(logPath: string, rec: SessionRecord): void {
   423→  const content = readFileSync(logPath, "utf8");
   424→
   425→  // Build the new header: AI summary as the H1, session ID + user in small text beneath
   426→  const title = rec.summary ?? `Session \`${rec.sessionId}\``;
   427→  const keywordsLine = rec.keywords?.length
   428→    ? `**Keywords:** ${rec.keywords.map((k) => `\`${k}\``).join(" ")}`
   429→    : "";
   430→
   431→  const userPart = rec.gitUserName && rec.gitUserEmail
   432→    ? ` · ${rec.gitUserName} &lt;${rec.gitUserEmail}&gt;`
   433→    : rec.gitUserName ? ` · ${rec.gitUserName}`
   434→    : rec.gitUserEmail ? ` · ${rec.gitUserEmail}`
   435→    : "";
   436→  const headerParts = [`# ${title}`, "", `<sub>\`${rec.sessionId}\`${userPart}</sub>`, ""];
   437→  if (keywordsLine) headerParts.push(keywordsLine, "");
   438→  const newHeader = headerParts.join("\n");
   439→
   440→  // Replace everything from the start of file up to the first event entry.
   441→  // Events start with ## , ### , or <details>.
   442→  const firstEventIdx = content.search(/^(?:#{2,3} |<details>)/m);
   443→  const body = firstEventIdx !== -1 ? content.slice(firstEventIdx) : "";
   444→  writeFileSync(logPath, newHeader + "\n" + body, "utf8");
   445→}
   446→
   447→function appendSessionLog(sessionsPath: string, input: HookInput, state: State, maxLogLines: number): string[] {
   448→  const logPath = sessionLogPath(sessionsPath, input.session_id);
   449→  mkdirSync(dirname(logPath), { recursive: true });
   450→
   451→  if (!existsSync(logPath)) {
   452→    writeFileSync(logPath, `# Session \`${input.session_id}\`\n\n`, "utf8");
   453→  }
   454→
   455→  // Patch the file header with summary + keywords once we have them
   456→  if (input.hook_event_name === "UserPromptSubmit") {
   457→    const rec = state.sessions[input.session_id];
   458→    if (rec) updateLogHeader(logPath, rec);
   459→  }
   460→
   461→  // ── Events to skip entirely ───────────────────────────────────────────────
   462→  if (SKIP_EVENTS.has(input.hook_event_name)) {
   463→    return [];
   464→  }
   465→
   466→  // ── PreToolUse: stash and write nothing yet ───────────────────────────────
   467→  if (input.hook_event_name === "PreToolUse") {
   468→    const pre = input as PreToolUseHookInput;
   469→    state.pendingToolUses[pre.tool_use_id] = {
   470→      tool_use_id: pre.tool_use_id,
   471→      tool_name: pre.tool_name,
   472→      tool_input: pre.tool_input,
   473→      startedAt: fmt(new Date().toISOString()),
   474→    };
   475→    return []; // nothing written to disk yet
   476→  }
   477→
   478→  // ── Log rotation (before any write) ──────────────────────────────────────
   479→  const rotatedPaths: string[] = [];
   480→  if (maxLogLines > 0) {
   481→    const archived = rotateSessionLog(logPath, maxLogLines);
   482→    if (archived) rotatedPaths.push(archived);
   483→  }
   484→
   485→  // ── PostToolUse / PostToolUseFailure: merge with stashed Pre ─────────────
   486→  if (
   487→    input.hook_event_name === "PostToolUse" ||
   488→    input.hook_event_name === "PostToolUseFailure"
   489→  ) {
   490→    const post = input as PostToolUseHookInput | PostToolUseFailureHookInput;
   491→    const pending = state.pendingToolUses[post.tool_use_id];
   492→    if (pending) {
   493→      delete state.pendingToolUses[post.tool_use_id];
   494→      appendFileSync(logPath, formatMergedToolUse(pending, post), "utf8");
   495→    } else {
   496→      // No matching Pre (e.g. state was cleared) — render as collapsible fallback
   497→      appendFileSync(logPath, formatCollapsibleEvent(input), "utf8");
   498→    }
   499→    return [...rotatedPaths, logPath];
   500→  }
   501→
   502→  // ── SubagentStart: create child log file ──────────────────────────────────
   503→  const changedPaths: string[] = [...rotatedPaths];
   504→  let childLogRelPath: string | undefined;
   505→
   506→  if (input.hook_event_name === "SubagentStart") {
   507→    const { agent_id, agent_type } = input as SubagentStartHookInput;
   508→    const childPath = sessionLogPath(sessionsPath, agent_id);
   509→    mkdirSync(dirname(childPath), { recursive: true });
   510→    if (!existsSync(childPath)) {
   511→      const parentLink = `[\`${input.session_id.slice(0, 8)}…\`](${input.session_id}.md)`;
   512→      writeFileSync(
   513→        childPath,
   514→        `# Subagent Session \`${agent_id}\`\n\n` +
   515→        `**Parent:** ${parentLink}  \n` +
   516→        `**Type:** \`${agent_type}\`\n\n`,
   517→        "utf8",
   518→      );
   519→      changedPaths.push(childPath);
   520→    }
   521→    childLogRelPath = `${agent_id}.md`;
   522→  }
   523→
   524→  // ── Important events: prominent H2 rendering ──────────────────────────────
   525→  if (input.hook_event_name === "UserPromptSubmit") {
   526→    appendFileSync(logPath, formatPromptEvent(input, state.sessions[input.session_id]), "utf8");
   527→  } else if (input.hook_event_name === "Stop" || input.hook_event_name === "Notification") {
   528→    appendFileSync(logPath, formatClaudeMessageEvent(input), "utf8");
   529→  } else if (IMPORTANT_EVENTS.has(input.hook_event_name)) {
   530→    appendFileSync(logPath, formatImportantEvent(input), "utf8");
   531→  } else {
   532→    // ── Everything else: collapsed ────────────────────────────────────────────
   533→    appendFileSync(logPath, formatCollapsibleEvent(input, childLogRelPath), "utf8");
   534→  }
   535→
   536→  changedPaths.push(logPath);
   537→  return changedPaths;
   538→}
   539→
   540→// ─── Git history ──────────────────────────────────────────────────────────────
   541→
   542→function ensureRepo(dir: string, sessionsFilename: string): void {
   543→  try {
   544→    execSync("git rev-parse --git-dir", { cwd: dir, stdio: "ignore" });
   545→  } catch {
   546→    execSync("git init", { cwd: dir, stdio: "ignore" });
   547→  }
   548→  // Always keep gitignore up to date — may need to add sessions/ on upgrade
   549→  const gitignore = join(dir, ".gitignore");
   550→  const desired =
   551→    `# Managed by claude-hook-handler\n` +
   552→    `*\n!.gitignore\n!${sessionsFilename}\n!sessions/\n!sessions/*.md\n`;
   553→  try {
   554→    if (readFileSync(gitignore, "utf8") !== desired) writeFileSync(gitignore, desired, "utf8");
   555→  } catch {
   556→    writeFileSync(gitignore, desired, "utf8");
   557→  }
   558→}
   559→
   560→function commitFiles(sessionsPath: string, paths: string[], message: string): void {
   561→  const dir = dirname(sessionsPath);
   562→  ensureRepo(dir, basename(sessionsPath));
   563→
   564→  for (const p of paths) spawnSync("git", ["add", p], { cwd: dir });
   565→
   566→  const diff = spawnSync("git", ["diff", "--cached", "--quiet"], { cwd: dir });
   567→  if (diff.status === 0) return;
   568→
   569→  spawnSync(
   570→    "git",
   571→    [
   572→      "-c", "user.name=claude-hook-handler",
   573→      "-c", "user.email=noreply@localhost",
   574→      "commit", "-m", message,
   575→    ],
   576→    { cwd: dir },
   577→  );
   578→}
   579→
   580→function buildCommitMessage(input: HookInput, state: State): string {
   581→  const id = input.session_id.slice(0, 8);
   582→  switch (input.hook_event_name) {
   583→    case "SessionStart": {
   584→      const rec = state.sessions[input.session_id];
   585→      const repo = rec?.repoName ? ` (${rec.repoName})` : "";
   586→      return `session started: ${id}${repo}`;
   587→    }
   588→    case "UserPromptSubmit": {
   589→      const rec = state.sessions[input.session_id];
   590→      const summary = rec?.summary ?? rec?.prompt?.slice(0, 60) ?? "";
   591→      return `session prompt: ${id}: ${summary}`;
   592→    }
   593→    case "SessionEnd":
   594→      return `session ended: ${id}`;
   595→    default: {
   596→      const count = Object.keys(state.sessions).length;
   597→      return `sessions: ${count} active`;
   598→    }
   599→  }
   600→}
   601→
   602→// ─── Prompt summarisation ─────────────────────────────────────────────────────
   603→
   604→interface PromptAnalysis {
   605→  summary: string;
   606→  keywords: string[];
   607→}
   608→
   609→async function analyse(prompt: string): Promise<PromptAnalysis> {
   610→  if (!process.env.ANTHROPIC_API_KEY) {
   611→    return truncateAnalysis(prompt);
   612→  }
   613→  try {
   614→    const client = new Anthropic();
   615→    const response = await client.messages.create({
   616→      model: "claude-haiku-4-5",
   617→      max_tokens: 120,
   618→      messages: [
   619→        {
   620→          role: "user",
   621→          content:
   622→            `Analyse the following user prompt. Reply with a JSON object only — no prose, no code fences.\n` +
   623→            `{\n` +
   624→            `  "summary": "<one sentence, 10 words max, no trailing punctuation>",\n` +
   625→            `  "keywords": ["<3-6 keywords: named entities, tools, concepts, actions>"]\n` +
   626→            `}\n\nPrompt:\n${prompt}`,
   627→        },
   628→      ],
   629→    });
   630→    const block = response.content[0];
   631→    if (block?.type === "text") {
   632→      // Strip markdown code fences in case the model wraps its JSON
   633→      const raw = block.text.trim()
   634→        .replace(/^```(?:json)?\s*/i, "")
   635→        .replace(/\s*```$/, "");
   636→      const parsed = JSON.parse(raw) as Partial<PromptAnalysis>;
   637→      return {
   638→        summary: String(parsed.summary ?? "").replace(/[.!?]$/, ""),
   639→        keywords: Array.isArray(parsed.keywords) ? parsed.keywords.map(String) : [],
   640→      };
   641→    }
   642→  } catch {
   643→    // fall through
   644→  }
   645→  return truncateAnalysis(prompt);
   646→}
   647→
   648→function truncateAnalysis(prompt: string): PromptAnalysis {
   649→  const firstLine = prompt.split("\n")[0]?.trim() ?? prompt;
   650→  return {
   651→    summary: firstLine.length > 80 ? firstLine.slice(0, 77) + "…" : firstLine,
   652→    keywords: [],
   653→  };
   654→}
   655→
   656→// ─── State mutation per event ─────────────────────────────────────────────────
   657→
   658→async function applyEvent(
   659→  state: State,
   660→  input: HookInput,
   661→  noSummary: boolean,
   662→  precomputed?: { summary: string; keywords: string[] },
   663→): Promise<void> {
   664→  const { session_id, hook_event_name, cwd } = input;
   665→  const now = new Date().toISOString();
   666→
   667→  switch (hook_event_name) {
   668→    case "SessionStart": {
   669→      const repo = detectRepo(cwd);
   670→      const parentSessionId = state.agentParents[session_id];
   671→      const user = gitUser();
   672→      state.sessions[session_id] = {
   673→        sessionId: session_id,
   674→        startedAt: now,
   675→        updatedAt: now,
   676→        cwd,
   677→        repoRoot: repo?.repoRoot,
   678→        repoName: repo?.repoName,
   679→        parentSessionId,
   680→        gitUserName: user.name,
   681→        gitUserEmail: user.email,
   682→      };
   683→      break;
   684→    }
   685→
   686→    case "SubagentStart": {
   687→      const { agent_id } = input as SubagentStartHookInput;
   688→      state.agentParents[agent_id] = session_id;
   689→      // Touch parent updatedAt
   690→      const existing = state.sessions[session_id];
   691→      if (existing) existing.updatedAt = now;
   692→      break;
   693→    }
   694→
   695→    case "UserPromptSubmit": {
   696→      const prompt = "prompt" in input ? String(input.prompt) : "";
   697→      const existing = state.sessions[session_id];
   698→      const { summary, keywords } = precomputed ?? (noSummary ? truncateAnalysis(prompt) : await analyse(prompt));
   699→      // Detect repo/user now if SessionStart was missed
   700→      const repo = existing?.repoRoot ? undefined : detectRepo(existing?.cwd ?? cwd);
   701→      const user = (existing?.gitUserName ?? existing?.gitUserEmail) ? undefined : gitUser();
   702→      state.sessions[session_id] = {
   703→        sessionId: session_id,
   704→        startedAt: existing?.startedAt ?? now,
   705→        updatedAt: now,
   706→        cwd: existing?.cwd ?? cwd,
   707→        repoRoot: existing?.repoRoot ?? repo?.repoRoot,
   708→        repoName: existing?.repoName ?? repo?.repoName,
   709→        parentSessionId: existing?.parentSessionId,
   710→        gitUserName: existing?.gitUserName ?? user?.name,
   711→        gitUserEmail: existing?.gitUserEmail ?? user?.email,
   712→        prompt,
   713→        summary,
   714→        keywords,
   715→      };
   716→      break;
   717→    }
   718→
   719→    case "SessionEnd": {
   720→      delete state.sessions[session_id];
   721→      break;
   722→    }
   723→
   724→    case "PreToolUse":
   725→      // Don't update sessions table — too frequent, makes updatedAt meaningless
   726→      break;
   727→
   728→    default: {
   729→      // Touch updatedAt for any other event
   730→      const existing = state.sessions[session_id];
   731→      if (existing) {
   732→        existing.updatedAt = now;
   733→      }
   734→      break;
   735→    }
   736→  }
   737→}
   738→
   739→// ─── stderr formatting ────────────────────────────────────────────────────────
   740→
   741→const EVENT_SYMBOL: Record<string, string> = {
   742→  PreToolUse:         "▶",
   743→  PostToolUse:        "✓",
   744→  PostToolUseFailure: "✗",
   745→  SessionStart:       "◉",
   746→  SessionEnd:         "◎",
   747→  Stop:               "■",
   748→  UserPromptSubmit:   "→",
   749→  Notification:       "◆",
   750→  Setup:              "⚙",
   751→  SubagentStart:      "▷",
   752→  SubagentStop:       "◁",
   753→  PermissionRequest:  "?",
   754→  PreCompact:         "⌃",
   755→};
   756→
   757→function formatForStderr(input: HookInput, blocked: boolean): string {
   758→  const ts = new Date().toISOString().replace("T", " ").slice(0, 23);
   759→  const name = input.hook_event_name;
   760→  const sym = EVENT_SYMBOL[name] ?? "◆";
   761→  const blockTag = blocked ? " \x1b[31m[BLOCKED]\x1b[0m" : "";
   762→
   763→  const lines = [`\x1b[1m[${ts}] ${sym} ${name}\x1b[0m${blockTag}`];
   764→
   765→  if ("tool_name" in input)
   766→    lines.push(`  tool:   \x1b[1m${input.tool_name}\x1b[0m`);
   767→  if ("tool_input" in input && input.tool_input !== undefined) {
   768→    const s = JSON.stringify(input.tool_input);
   769→    lines.push(`  input:  ${s.length > 120 ? s.slice(0, 120) + "…" : s}`);
   770→  }
   771→  if ("tool_response" in input && input.tool_response !== undefined) {
   772→    const s = JSON.stringify(input.tool_response);
   773→    lines.push(`  output: ${s.length > 120 ? s.slice(0, 120) + "…" : s}`);
   774→  }
   775→  if ("error" in input && input.error)
   776→    lines.push(`  error:  \x1b[31m${input.error}\x1b[0m`);
   777→  if ("prompt" in input && input.prompt)
   778→    lines.push(`  prompt: ${String(input.prompt).slice(0, 100)}`);
   779→  if ("message" in input && input.message)
   780→    lines.push(`  msg:    ${String(input.message)}`);
   781→  if ("reason" in input && input.reason)
   782→    lines.push(`  reason: ${String(input.reason)}`);
   783→  if ("source" in input && input.source)
   784→    lines.push(`  source: ${String(input.source)}`);
   785→
   786→  lines.push(`  session: \x1b[2m${input.session_id.slice(0, 8)}…\x1b[0m`);
   787→  return lines.join("\n");
   788→}
   789→
   790→// ─── Tool blocking ────────────────────────────────────────────────────────────
   791→
   792→function shouldBlock(input: HookInput, patterns: RegExp[]): boolean {
   793→  if (input.hook_event_name !== "PreToolUse" || patterns.length === 0)
   794→    return false;
   795→  const name = (input as PreToolUseHookInput).tool_name ?? "";
   796→  return patterns.some((re) => re.test(name));
   797→}
   798→
   799→function buildResponse(blocked: boolean, reason: string): SyncHookJSONOutput {
   800→  return blocked ? { decision: "block", reason } : {};
   801→}
   802→
   803→// ─── SQLite event log ─────────────────────────────────────────────────────────
   804→
   805→import type { PrismaClient } from "../prisma/generated/client/index.js";
   806→
   807→/**
   808→ * Insert one event record into the SQLite database.
   809→ * For UserPromptSubmit, also stores summary and keywords from the session state.
   810→ */
   811→async function writeEventLog(
   812→  db: PrismaClient,
   813→  input: HookInput,
   814→  blocked: boolean,
   815→  state: State,
   816→): Promise<void> {
   817→  const session = state.sessions[input.session_id];
   818→  await db.event.create({
   819→    data: {
   820→      event: input.hook_event_name,
   821→      sessionId: input.session_id,
   822→      blocked,
   823→      data: JSON.stringify(input),
   824→      summary: input.hook_event_name === "UserPromptSubmit"
   825→        ? (session?.summary ?? null)
   826→        : null,
   827→      keywords: input.hook_event_name === "UserPromptSubmit" && session?.keywords
   828→        ? JSON.stringify(session.keywords)
   829→        : null,
   830→    },
   831→  });
   832→}
   833→
   834→// ─── Reconstruction ───────────────────────────────────────────────────────────
   835→
   836→/**
   837→ * Replay the SQLite event log and rebuild all markdown files from scratch.
   838→ * Uses stored summary/keywords from each record; calls AI for any that are missing
   839→ * unless noSummary is true.
   840→ */
   841→async function runReconstruct(
   842→  db: PrismaClient,
   843→  sessionsPath: string,
   844→  maxLogLines: number,
   845→  noSummary: boolean,
   846→): Promise<void> {
   847→  // Clear existing markdown output so we start fresh
   848→  const absSessions = expandHome(sessionsPath);
   849→  const sessionsDir = join(dirname(absSessions), "sessions");
   850→  if (existsSync(sessionsDir)) {
   851→    for (const f of readdirSync(sessionsDir)) {
   852→      if (f.endsWith(".md")) unlinkSync(join(sessionsDir, f));
   853→    }
   854→  }
   855→  if (existsSync(absSessions)) unlinkSync(absSessions);
   856→
   857→  const events = await db.event.findMany({ orderBy: { timestamp: "asc" } });
   858→
   859→  const state: State = { sessions: {}, agentParents: {}, pendingToolUses: {} };
   860→  let replayed = 0;
   861→  let skipped = 0;
   862→  let filled = 0;
   863→
   864→  for (const event of events) {
   865→    let input: HookInput;
   866→    try {
   867→      input = JSON.parse(event.data) as HookInput;
   868→    } catch {
   869→      skipped++;
   870→      continue;
   871→    }
   872→
   873→    if (!input?.hook_event_name || input.hook_event_name === "Setup") {
   874→      continue;
   875→    }
   876→
   877→    const precomputed = event.summary !== null
   878→      ? { summary: event.summary, keywords: event.keywords ? (JSON.parse(event.keywords) as string[]) : [] }
   879→      : undefined;
   880→
   881→    await applyEvent(state, input, noSummary, precomputed);
   882→
   883→    // If AI filled in missing summary/keywords, backfill into the DB record
   884→    if (!precomputed && input.hook_event_name === "UserPromptSubmit") {
   885→      const session = state.sessions[input.session_id];
   886→      if (session?.summary !== undefined) {
   887→        await db.event.update({
   888→          where: { id: event.id },
   889→          data: {
   890→            summary: session.summary,
   891→            keywords: JSON.stringify(session.keywords ?? []),
   892→          },
   893→        });
   894→        filled++;
   895→      }
   896→    }
   897→
   898→    writeMarkdown(absSessions, state);
   899→    appendSessionLog(absSessions, input, state, maxLogLines);
   900→    replayed++;
   901→  }
   902→
   903→  // Write state back to DB
   904→  await writeStateToDb(db, state);
   905→
   906→  if (filled > 0) {
   907→    process.stderr.write(`claude-hook-handler reconstruct: filled ${filled} missing summaries\n`);
   908→  }
   909→  process.stderr.write(
   910→    `claude-hook-handler reconstruct: replayed ${replayed} events` +
   911→      (skipped ? `, skipped ${skipped} malformed records` : "") +
   912→      `\n  sessions → ${absSessions}\n`,
   913→  );
   914→}
   915→
   916→// ─── Migration: NDJSON → SQLite ───────────────────────────────────────────────
   917→
   918→interface LegacyEventRecord {
   919→  timestamp: string;
   920→  event: string;
   921→  blocked: boolean;
   922→  data: HookInput;
   923→  summary?: string;
   924→  keywords?: string[];
   925→}
   926→
   927→async function runMigrate(
   928→  eventsPath: string,
   929→  db: PrismaClient,
   930→  sessionsPath: string,
   931→  maxLogLines: number,
   932→  noSummary: boolean,
   933→): Promise<void> {
   934→  const absEvents = expandHome(eventsPath);
   935→  if (!existsSync(absEvents)) {
   936→    process.stderr.write(`claude-hook-handler migrate: no NDJSON file found at ${absEvents}\n`);
   937→    process.exit(1);
   938→  }
   939→
   940→  const rawLines = readFileSync(absEvents, "utf8").split("\n");
   941→  let inserted = 0;
   942→  let skipped = 0;
   943→
   944→  for (const line of rawLines) {
   945→    if (!line.trim()) continue;
   946→
   947→    let record: LegacyEventRecord;
   948→    try {
   949→      record = JSON.parse(line) as LegacyEventRecord;
   950→    } catch {
   951→      skipped++;
   952→      continue;
   953→    }
   954→
   955→    if (!record.data?.hook_event_name) {
   956→      skipped++;
   957→      continue;
   958→    }
   959→
   960→    try {
   961→      await db.event.create({
   962→        data: {
   963→          timestamp: new Date(record.timestamp),
   964→          event: record.event,
   965→          sessionId: record.data.session_id,
   966→          blocked: record.blocked ?? false,
   967→          data: JSON.stringify(record.data),
   968→          summary: record.summary ?? null,
   969→          keywords: record.keywords ? JSON.stringify(record.keywords) : null,
   970→        },
   971→      });
   972→      inserted++;
   973→    } catch {
   974→      skipped++;
   975→    }
   976→  }
   977→
   978→  process.stderr.write(
   979→    `claude-hook-handler migrate: inserted ${inserted} events` +
   980→      (skipped ? `, skipped ${skipped} lines` : "") +
   981→      `\n`,
   982→  );
   983→
   984→  // Rebuild sessions/state from the newly inserted events
   985→  process.stderr.write(`claude-hook-handler migrate: running reconstruct...\n`);
   986→  await runReconstruct(db, sessionsPath, maxLogLines, noSummary);
   987→}
   988→
   989→// ─── stdin ────────────────────────────────────────────────────────────────────
   990→
   991→async function readStdin(): Promise<string> {
   992→  if (process.stdin.isTTY) {
   993→    process.stderr.write(
   994→      "claude-hook-handler: no stdin detected.\n" +
   995→        "This program is called by Claude Code hooks, not directly.\n" +
   996→        "Run with --help for configuration instructions.\n",
   997→    );
   998→    process.exit(1);
   999→  }
  1000→  const chunks: Buffer[] = [];
  1001→  for await (const chunk of process.stdin) chunks.push(chunk as Buffer);
  1002→  return Buffer.concat(chunks).toString("utf8");
  1003→}
